// Lamport Logical Clock
// Each process Pi maintains integer Ci

// On local event at process Pi:
Ci = Ci + 1
timestamp = Ci
// record event with timestamp

// On sending message M from Pi:
Ci = Ci + 1
timestamp = Ci
send(M, timestamp)

// On receiving message M at Pi with timestamp T:
Ci = max(Ci, T) + 1
timestamp = Ci
deliver(M)

// Total order delivery:
when a message is received:
 place in priority queue sorted by timestamp
deliver in increasing timestamp order

// Vector Clock for n processes
// Process Pi maintains vector Vi[0..n-1]

// Initialize:
Vi[j] = 0 for all j

// On local event at Pi:
Vi[i] = Vi[i] + 1
// event has vector Vi

// On sending message M from Pi:
Vi[i] = Vi[i] + 1
send(M, Vi)

// On receiving message M at Pi with vector Vm:
for j = 0 to n-1:
 Vi[j] = max(Vi[j], Vm[j])
Vi[i] = Vi[i] + 1
deliver(M)

// Compare vectors V1 and V2:
isLessThanOrEqual(V1, V2):
 for all j: if V1[j] > V2[j] return false
 return true

// Events e1, e2 concurrent if:
// not (V1 ≤ V2 or V2 ≤ V1)

// Causal Order Broadcast
// Each process Pi maintains vector Vi
// and deliver queue Q

// Initialize:
Vi[j] = 0 for all j

// Broadcast message M:
Vi[i] = Vi[i] + 1
send((M, Vi), to all processes)

// On receive (M, Vm) from Pj:
// Check if prerequisites satisfied
ready = true
for k = 0 to n-1:
 if k ≠ i and Vm[k] > Vi[k] + (j == i ? 0 : 0):
 // Wait for missing events from Pk
 ready = false
 break

if ready:
 Vi[j] = Vm[j]
 Vi[i] = Vi[i] + 1
 deliver(M)
else:
 queue message for later delivery

// Version Conflict Detection using Vector Clocks
// Each document has version vector VV

// Update document at Pi:
Vi[i] = Vi[i] + 1
VV = Vi
save(document, VV)

// Receive update with version Vnew:
// Check if our version is ancestor of new
isAncestor(myVV, newVV):
 for all j: if myVV[j] > newVV[j] return false
 return true

// Check for conflict
if isAncestor(myVV, newVV):
 // New version supersedes ours - accept
 myVV = newVV
 apply(newVV.data)
else if isAncestor(newVV, myVV):
 // Our version supersedes new - ignore
 discard(newVV)
else:
 // Concurrent versions - CONFLICT!
 // Need conflict resolution
 conflict = true
 invokeConflictResolution(myVV, newVV)
